php artisan prisoner:add '{"name":"Yunseo Chung","first_name":"Yunseo","last_name":"Chung","description":"Yunseo Chung is a 21-year-old Columbia University undergraduate, a green-card holder who was brought to the United States from South Korea at age 7. She was arrested at and given a citation during a March 5, 2025 sit-in at Barnard College protesting Columbias disciplinary actions against pro-Palestine student organizers. After Mahmoud Khalils March 8 ICE arrest, federal officers attempted twice to detain her — once at her family home in New Jersey and once with a search warrant at her Columbia residence hall. Her attorneys filed a TRO, and Judge Naomi Reice Buchwald of the U.S. District Court for the Southern District of New York granted a temporary restraining order blocking ICE from arresting her. The TRO was extended on June 5, 2025; in October 2025 the court ruled that the State Departments use of the foreign-policy designation against her was unconstitutional retaliation for First Amendment-protected activity. The Department of Homeland Security has confirmed that the designation against her was personally signed by Secretary of State Marco Rubio.","state":"New York","race":"Asian","gender":"Female","ideologies":["Palestine solidarity","First Amendment"],"affiliation":["Columbia University","Columbia University Apartheid Divest"],"era":"2020s","in_custody":false,"released":true,"cases":[{"institution_name":"(detention blocked by federal court order)","institution_state":"New York","charges":"INA 8 USC 1227(a)(4)(C) - U.S. Secretary of State foreign-policy designation, based on March 5, 2025 Columbia/Barnard pro-Palestine sit-in citation","arrest_date":"2025-03-13","sentence":"Federal court TRO blocked ICE from detaining her; in October 2025 federal court ruled the foreign-policy designation against her was unconstitutional retaliation for protected speech","convicted":"No - civil immigration action; ICE detention blocked by federal court order"}]}' || true

