php artisan prisoner:add '{"name":"Ranjani Srinivasan","first_name":"Ranjani","last_name":"Srinivasan","description":"Dr. Ranjani Srinivasan is a 37-year-old Indian-national PhD candidate in Urban Planning at Columbia University and a former Fulbright scholar who had been studying in the United States since 2016. She was given two summonses for her presence at Columbia pro-Palestine protests in spring 2024 (the charges were ultimately dismissed); she did not disclose them on her most recent F-1 visa renewal. On March 5, 2025 the U.S. Department of State revoked her student visa under the foreign-policy designation, citing her alleged support for Hamas. ICE and DHS officers came to her Columbia apartment on March 7, 2025 attempting to arrest her. She fled the apartment, packed a single bag, and on March 11, 2025 boarded a flight from JFK to Toronto, Canada, where she stayed with friends and family.\n\nDHS Secretary Kristi Noem subsequently posted a video on X claiming that Srinivasan had used the U.S. Customs and Border Protection CBP Home app to self-deport — a characterization Srinivasan and her attorneys reject; she had simply left the country to avoid the ICE detention that was clearly imminent. Her departure is among the most prominent cases of pre-emptive flight from the U.S. by an academic Palestine-solidarity organizer in the 2025 wave.","state":"New York","race":"Asian","gender":"Female","ideologies":["Palestine solidarity","First Amendment"],"affiliation":["Columbia University"],"era":"2020s","in_custody":false,"released":false,"in_exile":true,"currently_in_exile":true,"imprisoned_or_exiled":true,"cases":[{"institution_name":"(fled to Canada to avoid ICE detention)","institution_state":"New York","charges":"INA foreign-policy designation by Secretary of State Marco Rubio; alleged failure to disclose Columbia-protest summonses on F-1 visa renewal","arrest_date":"2025-03-07","in_exile_since":"2025-03-11","sentence":"Visa revoked March 5, 2025; ICE attempted arrest March 7; fled to Canada via JFK March 11, 2025","convicted":"No - civil immigration action; never detained"}]}' || true

