php artisan prisoner:add '{"name":"Rasha Alawieh","first_name":"Rasha","last_name":"Alawieh","description":"Dr. Rasha Alawieh is a Lebanese kidney transplant specialist and assistant professor at Brown Medicine who held a valid H-1B work visa for her position at Brown. On March 14, 2025, returning to the United States from a family visit to Lebanon, she was detained on arrival at Logan International Airport in Boston. Customs and Border Protection officers questioned her for over 36 hours. The government cited photographs of Hezbollah leader Hasan Nasrallah, Iranian Supreme Leader Ali Khamenei, and Hezbollah fighters in her phones deleted-items folder. Alawieh acknowledged in the airport interview that she had attended Nasrallahs funeral in February 2025 because of his religious position in the Shia community.\n\nU.S. District Judge Leo Sorokin in the District of Massachusetts issued an emergency order on March 14 barring her removal from Massachusetts without 48 hours notice to the court. CBP officers nonetheless put her on a flight to Paris before the court order was, by their account, received; she was back in Lebanon by March 16, 2025 — deported in apparent violation of a federal court order. The deportation triggered a five-year U.S. re-entry ban. Her case became a leading example of the 2025 administrations willingness to override federal court orders blocking removals. In October 2025 Judge Sorokin dismissed her lawsuit, ruling he lacked authority to remove the five-year ban.","state":"Massachusetts","race":"Arab","gender":"Female","ideologies":["Shia religious solidarity","Palestine solidarity"],"affiliation":["Brown Medicine","Brown University"],"era":"2020s","in_custody":false,"released":false,"in_exile":true,"currently_in_exile":true,"imprisoned_or_exiled":true,"cases":[{"institution_name":"Logan International Airport (CBP detention) → deported to Lebanon","institution_state":"Massachusetts","charges":"H-1B visa revoked at port of entry under INA inadmissibility; deportation in apparent violation of federal court order","arrest_date":"2025-03-14","incarceration_date":"2025-03-14","release_date":"2025-03-16","in_exile_since":"2025-03-16","sentence":"36+ hours airport detention; deported to Lebanon via Paris March 16, 2025; 5-year US re-entry ban","convicted":"No - civil immigration action; deported in apparent violation of federal court order"}]}' || true

